python3 -c "
import json
import sys

with open('manifest.json', 'r') as f:
    manifest = json.load(f)
with open('schema.json', 'r') as f:
    schema = json.load(f)

# Manual validation
errors = []

# Check required fields
if 'release' not in manifest:
    errors.append('Missing required field: release')
if 'components' not in manifest:
    errors.append('Missing required field: components')

# Check for additional properties
if set(manifest.keys()) > {'release', 'components'}:
    errors.append(f'Additional properties not allowed: {set(manifest.keys()) - {\"release\", \"components\"}}')

# Validate release format
if 'release' in manifest:
    import re
    if not re.match('^v[0-9]+\.[0-9]+\.[0-9]+$', manifest['release']):
        errors.append(f'Invalid release format: {manifest[\"release\"]}')

# Validate components
if 'components' in manifest:
    if not isinstance(manifest['components'], list):
        errors.append('components must be an array')
    elif len(manifest['components']) != 3:
        errors.append(f'components must have exactly 3 items, got {len(manifest[\"components\"])}')
    else:
        for i, comp in enumerate(manifest['components']):
            if not isinstance(comp, dict):
                errors.append(f'Component {i} is not an object')
                continue

            # Check required fields
            if 'name' not in comp:
                errors.append(f'Component {i} missing required field: name')
            if 'version' not in comp:
                errors.append(f'Component {i} missing required field: version')

            # Check additional properties
            if set(comp.keys()) > {'name', 'version'}:
                errors.append(f'Component {i} has additional properties: {set(comp.keys()) - {\"name\", \"version\"}}')

            # Validate name
            if 'name' in comp and (not isinstance(comp['name'], str) or len(comp['name']) < 1):
                errors.append(f'Component {i} name must be a non-empty string')

            # Validate version format
            if 'version' in comp:
                if not re.match('^[0-9]+\.[0-9]+\.[0-9]+$', comp['version']):
                    errors.append(f'Component {i} version \"{comp[\"version\"]}\" does not match semver pattern')

if errors:
    print('✗ Validation errors:')
    for error in errors:
        print(f'  - {error}')
    sys.exit(1)
else:
    print('✓ manifest.json validates against schema.json')
"
